import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Building a Subtractive Synth","description":"","frontmatter":{},"headers":[],"relativePath":"guides/subtractive-synth.md","filePath":"guides/subtractive-synth.md"}'),s={name:"guides/subtractive-synth.md"};function i(l,e,d,r,c,h){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="building-a-subtractive-synth" tabindex="-1">Building a Subtractive Synth <a class="header-anchor" href="#building-a-subtractive-synth" aria-label="Permalink to &quot;Building a Subtractive Synth&quot;">​</a></h1><p>This guide walks through building a classic subtractive synthesiser voice controlled by MIDI.</p><h2 id="the-signal-chain" tabindex="-1">The Signal Chain <a class="header-anchor" href="#the-signal-chain" aria-label="Permalink to &quot;The Signal Chain&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MIDI In -&gt; Oscillator -&gt; Filter -&gt; VCA -&gt; Stereo Out</span></span>
<span class="line"><span>              ^             ^        ^</span></span>
<span class="line"><span>              |             |        |</span></span>
<span class="line"><span>           [note]      [cutoff]   [gain]</span></span>
<span class="line"><span>              |             |        |</span></span>
<span class="line"><span>           MIDI In      ADSR 1    ADSR 2</span></span>
<span class="line"><span>            (note)      (gate)    (gate)</span></span></code></pre></div><h2 id="step-by-step" tabindex="-1">Step by Step <a class="header-anchor" href="#step-by-step" aria-label="Permalink to &quot;Step by Step&quot;">​</a></h2><h3 id="_1-add-the-sound-source" tabindex="-1">1. Add the Sound Source <a class="header-anchor" href="#_1-add-the-sound-source" aria-label="Permalink to &quot;1. Add the Sound Source&quot;">​</a></h3><p>Add an <strong>Oscillator</strong> module. In the inspector, draw a waveform or select &quot;saw&quot; for a harmonically rich starting point.</p><h3 id="_2-add-the-filter" tabindex="-1">2. Add the Filter <a class="header-anchor" href="#_2-add-the-filter" aria-label="Permalink to &quot;2. Add the Filter&quot;">​</a></h3><p>Add a <strong>Filter</strong> module. The lowpass output (<code>lpL</code>, <code>lpR</code>) removes high harmonics -- this is the core of subtractive synthesis. Set the initial cutoff to around 2000 Hz.</p><h3 id="_3-add-the-amplifier" tabindex="-1">3. Add the Amplifier <a class="header-anchor" href="#_3-add-the-amplifier" aria-label="Permalink to &quot;3. Add the Amplifier&quot;">​</a></h3><p>Add a <strong>VCA</strong> module. This controls the volume envelope of the sound.</p><h3 id="_4-add-the-output" tabindex="-1">4. Add the Output <a class="header-anchor" href="#_4-add-the-output" aria-label="Permalink to &quot;4. Add the Output&quot;">​</a></h3><p>Add a <strong>Stereo Out</strong> and connect: Oscillator L -&gt; Filter inL, Filter lpL -&gt; VCA inL, VCA outL -&gt; Stereo Out L (and same for R).</p><h3 id="_5-add-midi-control" tabindex="-1">5. Add MIDI Control <a class="header-anchor" href="#_5-add-midi-control" aria-label="Permalink to &quot;5. Add MIDI Control&quot;">​</a></h3><p>Add a <strong>MIDI In</strong> module. Connect:</p><ul><li>MIDI In <code>note</code> -&gt; Oscillator <code>note</code> (this carries pitch + gate + velocity)</li></ul><h3 id="_6-add-envelopes" tabindex="-1">6. Add Envelopes <a class="header-anchor" href="#_6-add-envelopes" aria-label="Permalink to &quot;6. Add Envelopes&quot;">​</a></h3><p>Add two <strong>ADSR</strong> modules:</p><p><strong>ADSR 1 (Filter envelope):</strong></p><ul><li>Connect MIDI In <code>gate</code> -&gt; ADSR 1 <code>gate</code></li><li>Connect ADSR 1 <code>out</code> -&gt; Filter <code>cutoff</code></li><li>Set: fast attack, medium decay, moderate sustain, medium release</li></ul><p><strong>ADSR 2 (Amplitude envelope):</strong></p><ul><li>Connect MIDI In <code>gate</code> -&gt; ADSR 2 <code>gate</code></li><li>Connect ADSR 2 <code>out</code> -&gt; VCA <code>gain</code></li><li>Set: instant attack, short decay, high sustain, short release</li></ul><h3 id="_7-upload-and-play" tabindex="-1">7. Upload and Play <a class="header-anchor" href="#_7-upload-and-play" aria-label="Permalink to &quot;7. Upload and Play&quot;">​</a></h3><p>Upload the patch and play your MIDI keyboard. Adjust the filter cutoff ADSR for brighter or darker tones.</p><h2 id="enhancements" tabindex="-1">Enhancements <a class="header-anchor" href="#enhancements" aria-label="Permalink to &quot;Enhancements&quot;">​</a></h2><ul><li>Add a <strong>Pot</strong> to control filter cutoff manually alongside the envelope</li><li>Add a <strong>Delay</strong> or <strong>Reverb</strong> after the VCA for space</li><li>Use a <strong>Poly Oscillator</strong> instead for chords (it has a built-in ADSR)</li><li>Add a second Oscillator detuned slightly for a fatter sound</li></ul>`,26)])])}const g=a(s,[["render",i]]);export{p as __pageData,g as default};
